import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useSubscription } from '../../contexts/SubscriptionContext';

const PricingPlans = () => {
  const [selectedTier, setSelectedTier] = useState(null);
  const [selectedInterval, setSelectedInterval] = useState('month');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);
  
  const { 
    createCheckoutSession, 
    subscription, 
    loading: subscriptionLoading 
  } = useSubscription();
  
  // Define pricing
  const plans = {
    basic: {
      name: 'Basic',
      priceMonthly: 0,
      priceYearly: 0,
      features: [
        'Access to basic workouts',
        'Health tracking',
        'Email support'
      ],
      recommended: false
    },
    premium: {
      name: 'Premium',
      priceMonthly: 14.99,
      priceYearly: 149.99,
      features: [
        'Everything in Basic',
        'Personalized workout plans',
        'Nutrition guidance',
        'Priority support'
      ],
      recommended: true
    },
    elite: {
      name: 'Elite',
      priceMonthly: 24.99,
      priceYearly: 249.99,
      features: [
        'Everything in Premium',
        'One-on-one coaching sessions',
        'Advanced health tracking',
        'Exclusive content'
      ],
      recommended: false
    }
  };
  
  const handleSelectPlan = async (tier, interval) => {
    console.log(`Selecting plan: ${tier} with billing cycle: ${interval}`);
    setSelectedTier(tier);
    setSelectedInterval(interval);
    
    // If selecting the free basic plan
    if (tier === 'basic') {
      // Handle free signup separately
      // This would typically redirect to a different endpoint
      return;
    }
    
    // For paid plans, create checkout session
    try {
      setIsLoading(true);
      setError(null);
      
      console.log('Creating checkout for', tier, 'with billing cycle', interval);
      const response = await createCheckoutSession(tier, interval);
      console.log('Checkout result:', response);
      
      if (!response.success) {
        setError(response.error || 'Failed to create checkout session');
        return;
      }
      
      // If there's a direct URL in the response, use it (recommended approach)
      if (response.url) {
        window.location.href = response.url;
        return;
      }
      
      // Otherwise, if just a session ID is returned
      if (response.sessionId) {
        // If you have Stripe.js initialized:
        if (window.Stripe) {
          const stripe = window.Stripe('pk_test_51R40QxGCjT8uHlI9WQdabIoRw4icN3pWYm7uzGh7BEOiXdbpCIEFrgOBqjrrPHQxJcUwScTYUWwe6dujC9lBoNi300saDYDTse');
          stripe.redirectToCheckout({ sessionId: response.sessionId });
        } else {
          // Fallback direct URL construction if Stripe.js isn't available
          window.location.href = `https://checkout.stripe.com/pay/${response.sessionId}`;
        }
      }
    } catch (error) {
      console.error('Error creating checkout:', error);
      setError('Failed to process your request. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };
  
  // Function to handle the simple test checkout
  const handleSimpleCheckout = async () => {
    try {
      console.log('Attempting simple test checkout...');
      setIsLoading(true);
      
      const response = await fetch('http://localhost:31415/api/stripe/simple-checkout', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify({})
      });
      
      const data = await response.json();
      console.log('Simple checkout response:', data);
      
      // Redirect to Stripe Checkout
      if (data.url) {
        window.location.href = data.url;
      } else if (data.sessionId) {
        // Fallback direct URL construction
        window.location.href = `https://checkout.stripe.com/pay/${data.sessionId}`;
      } else {
        setError('Could not create checkout session');
      }
    } catch (error) {
      console.error('Simple checkout error:', error);
      setError('Failed to connect to the server');
    } finally {
      setIsLoading(false);
    }
  };
  
  return (
    <div className="container mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold mb-6 text-center">Subscription Plans</h1>
      
      {/* Test button for debugging */}
      <div className="flex justify-center mb-6">
        <button
          onClick={handleSimpleCheckout}
          disabled={isLoading}
          className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50"
        >
          {isLoading ? 'Processing...' : 'Test Simple Checkout'}
        </button>
      </div>
      
      {/* Error message */}
      {error && (
        <div className="bg-red-100 text-red-700 p-4 rounded mb-6">
          {error}
        </div>
      )}
      
      {/* Billing toggle */}
      <div className="flex justify-center mb-8">
        <div className="inline-flex items-center bg-gray-100 rounded-full p-1">
          <button
            className={`py-2 px-4 rounded-full ${selectedInterval === 'month' ? 'bg-blue-600 text-white' : 'text-gray-700'}`}
            onClick={() => setSelectedInterval('month')}
          >
            Monthly
          </button>
          <button
            className={`py-2 px-4 rounded-full ${selectedInterval === 'year' ? 'bg-blue-600 text-white' : 'text-gray-700'}`}
            onClick={() => setSelectedInterval('year')}
          >
            Yearly <span className="text-xs text-green-600 font-bold">Save 15%</span>
          </button>
        </div>
      </div>
      
      {/* Plans */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {Object.entries(plans).map(([tier, plan]) => (
          <div 
            key={tier} 
            className={`border rounded-lg overflow-hidden ${
              plan.recommended ? 'border-indigo-500 shadow-md' : 'border-gray-200'
            }`}
          >
            {plan.recommended && (
              <div className="bg-indigo-500 text-white text-center py-2 font-semibold">
                Recommended
              </div>
            )}
            
            <div className="p-6">
              <h3 className="text-xl font-bold mb-4">{plan.name}</h3>
              
              <div className="mb-4">
                <span className="text-3xl font-bold">
                  ${selectedInterval === 'month' ? plan.priceMonthly : plan.priceYearly}
                </span>
                {plan.priceMonthly > 0 && (
                  <span className="text-gray-500">
                    /{selectedInterval}
                  </span>
                )}
              </div>
              
              <ul className="mb-6 space-y-2">
                {plan.features.map((feature, index) => (
                  <li key={index} className="flex items-start">
                    <svg className="h-5 w-5 text-green-500 mt-0.5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
                    </svg>
                    {feature}
                  </li>
                ))}
              </ul>
              
              <button
                onClick={() => handleSelectPlan(tier, selectedInterval)}
                disabled={isLoading || (subscriptionLoading && !subscription)}
                className={`w-full py-2 px-4 rounded-md font-medium ${
                  tier === 'basic'
                    ? 'bg-gray-600 hover:bg-gray-700 text-white'
                    : tier === 'premium'
                    ? 'bg-indigo-600 hover:bg-indigo-700 text-white'
                    : 'bg-purple-600 hover:bg-purple-700 text-white'
                } disabled:opacity-50`}
              >
                {isLoading ? 'Processing...' : tier === 'basic' ? 'Get Started' : 'Subscribe'}
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PricingPlans;
